{
var iconInput = inputs.Length > 0 ? inputs[0] : null;
var width = GetFloat(parameters, "width", 0.4f);
var height = GetFloat(parameters, "height", 0.15f);
var cornerR = GetFloat(parameters, "cornerRadius", 0.04f);
var btnColor = GetColor(parameters, "buttonColor", Color.FromRgb(65, 120, 200));
var borderColor = GetColor(parameters, "borderColor", Color.FromRgb(100, 150, 220));
var state = GetChoice(parameters, "state", "normal");
var offsetX = GetFloat(parameters, "offsetX", 0f);
var offsetY = GetFloat(parameters, "offsetY", 0f);

var tileSize = context.TileSize;
var buffer = new PixelBuffer(tileSize, tileSize);

var bR = btnColor.R / 255f; var bG = btnColor.G / 255f; var bB = btnColor.B / 255f;
var oR = borderColor.R / 255f; var oG = borderColor.G / 255f; var oB = borderColor.B / 255f;

var halfSize = tileSize * 0.5f;
var btnW = tileSize * width * 0.5f;
var btnH = tileSize * height * 0.5f;
var cornerPx = tileSize * cornerR;
var cx = halfSize + offsetX * tileSize;
var cy = halfSize + offsetY * tileSize;

// State adjustment
var brightnessMul = state switch
{
    "hover" => 1.15f,
    "pressed" => 0.8f,
    _ => 1f
};
var yOffset = state == "pressed" ? 1 : 0;

buffer.ParallelForEachPixel((x, y) =>
{
    var px = x + 0.5f - cx;
    var py = y + 0.5f - cy + yOffset;

    var ax = MathF.Abs(px);
    var ay = MathF.Abs(py);

    if (ax > btnW || ay > btnH) return;

    // Rounded rectangle SDF
    var rx = Math.Max(0f, ax - (btnW - cornerPx));
    var ry = Math.Max(0f, ay - (btnH - cornerPx));
    var cornerDist = MathF.Sqrt(rx * rx + ry * ry);

    if (cornerDist > cornerPx) return;

    var isBorder = cornerDist > cornerPx - 1.5f || ax > btnW - 1.5f || ay > btnH - 1.5f;

    if (isBorder)
    {
        var bevel = ax < btnW * 0.5f && ay < btnH * 0.5f ? 1.3f : 0.7f;
        buffer.SetPixel(x, y,
            Math.Clamp(oR * bevel * brightnessMul, 0f, 1f),
            Math.Clamp(oG * bevel * brightnessMul, 0f, 1f),
            Math.Clamp(oB * bevel * brightnessMul, 0f, 1f), 1f);
        return;
    }

    // Body gradient
    var gradY = py / btnH;
    var shade = state == "pressed" ? 0.8f : (0.8f - gradY * 0.3f);
    var finalMul = shade * brightnessMul;

    buffer.SetPixel(x, y,
        Math.Clamp(bR * finalMul, 0f, 1f),
        Math.Clamp(bG * finalMul, 0f, 1f),
        Math.Clamp(bB * finalMul, 0f, 1f), 1f);

    // Icon overlay
    if (iconInput != null && ax < btnW * 0.5f && ay < btnH * 0.5f)
    {
        var ix = (int)MathF.Round((px / (btnW * 0.5f) + 1f) * 0.5f * (iconInput.Width - 1));
        var iy = (int)MathF.Round((py / (btnH * 0.5f) + 1f) * 0.5f * (iconInput.Height - 1));
        ix = Math.Clamp(ix, 0, iconInput.Width - 1);
        iy = Math.Clamp(iy, 0, iconInput.Height - 1);
        var (ir, ig, ib, ia) = iconInput.GetPixel(ix, iy);
        if (ia > 0.5f)
        {
            // Blend icon over button
            buffer.SetPixel(x, y,
                ir * ia + bR * finalMul * (1f - ia),
                ig * ia + bG * finalMul * (1f - ia),
                ib * ia + bB * finalMul * (1f - ia), 1f);
        }
    }
});

return buffer;
}
